import { useState, useRef, useEffect } from "react";

// ─── Multi-user auth ──────────────────────────────────────────────────────────
// Module-level current user — set once on login, never changes during a session
let _currentUser = null;
try {
  const s = sessionStorage.getItem("wlg_session");
  if (s) _currentUser = JSON.parse(s);
} catch {}

function getCurrentUser() { return _currentUser; }
function setCurrentUser(u) {
  _currentUser = u;
  try {
    if (u) sessionStorage.setItem("wlg_session", JSON.stringify(u));
    else sessionStorage.removeItem("wlg_session");
  } catch {}
}

// Storage key helper — always prefix with username
function sk(key) {
  const u = _currentUser ? _currentUser.username : "default";
  return `${u}_${key}`;
}

const USERS = [
  { username: "admin",     displayName: "Admin",            hash: "64e2265cfb0e9f75fbe1387b1942938b7411ab7f4c51d9278e9ed7de16c88a10" }, // WLG2026!
  { username: "engineer1", displayName: "Engineer 1",       hash: "cb2ca81bad82c5098a9e8776a083bf8f5345b018c5e6c0837a6b0ebd9e1c0ff5" }, // Engineer1!
  { username: "engineer2", displayName: "Engineer 2",       hash: "444425e5bd7383f1073cbc0a6e75b8836cb5baa7e437d4d00994374e62b967ff" }, // Engineer2!
];

async function hashPassword(password) {
  try {
    const buf = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(password));
    return [...new Uint8Array(buf)].map(x => x.toString(16).padStart(2,"0")).join("");
  } catch { return ""; }
}

// ─── New user notification via EmailJS ───────────────────────────────────────
// EmailJS credentials — replace these with your own from emailjs.com
const EMAILJS_SERVICE_ID  = "service_wlg";       // your EmailJS service ID
const EMAILJS_TEMPLATE_ID = "template_newuser";  // your EmailJS template ID
const EMAILJS_PUBLIC_KEY  = "YOUR_PUBLIC_KEY";   // your EmailJS public key

async function sendNewUserNotification(username, profile) {
  try {
    const payload = {
      service_id:  EMAILJS_SERVICE_ID,
      template_id: EMAILJS_TEMPLATE_ID,
      user_id:     EMAILJS_PUBLIC_KEY,
      template_params: {
        to_email:      "westlothiangas@gmail.com",
        username:      username,  // this is their email address
        engineer_name: profile.engineerName  || "",
        company_name:  profile.companyName   || "",
        gas_safe_no:   profile.gasSafeNo     || "",
        engineer_id:   profile.gasId         || "",
        company_addr:  profile.companyAddr   || "",
        company_post:  profile.companyPostcode|| "",
        company_tel:   profile.companyTel    || "",
        company_email: profile.companyEmail  || "",
        registered_at: new Date().toLocaleString("en-GB"),
      }
    };
    const res = await fetch("https://api.emailjs.com/api/v1.0/email/send", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    if (!res.ok) console.warn("EmailJS notification failed:", res.status);
  } catch (e) {
    console.warn("EmailJS notification error:", e);
  }
}
