function BmkStepMeasure({ data, onChange, onNext, onBack, onHome }) {
  const inp = (key, ph, suffix) => (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"10px 0", borderBottom:"1px solid #f0f0f0" }}>
      <div style={{ flex:1, fontSize:14, color:"#444", paddingRight:12 }}>{ph}</div>
      <div style={{ display:"flex", alignItems:"center", gap:6 }}>
        <input value={data[key]||""} onChange={e=>onChange({...data,[key]:e.target.value})} placeholder=""
          style={{ width:80, padding:"8px 10px", border:"1px solid #ddd", borderRadius:8, fontSize:14, outline:"none", textAlign:"right" }}/>
        {suffix && <span style={{ fontSize:12, color:"#888", minWidth:30 }}>{suffix}</span>}
      </div>
    </div>
  );
  const gasRate = (keyFt, keyM, label) => (
    <div style={{ padding:"10px 0", borderBottom:"1px solid #f0f0f0" }}>
      <div style={{ fontSize:14, color:"#444", marginBottom:8 }}>{label}</div>
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
        <div>
          <div style={{ fontSize:11, color:"#888", textAlign:"center", marginBottom:4 }}>FT3</div>
          <input value={data[keyFt]||""} onChange={e=>onChange({...data,[keyFt]:e.target.value})} placeholder="FT3"
            style={{ width:"100%", padding:"10px", border:"2px solid #ddd", borderRadius:8, fontSize:14, outline:"none", textAlign:"center", boxSizing:"border-box", background:data[keyFt]?"#fff":"#fafafa" }}/>
        </div>
        <div>
          <div style={{ fontSize:11, color:"#888", textAlign:"center", marginBottom:4 }}>M3</div>
          <input value={data[keyM]||""} onChange={e=>onChange({...data,[keyM]:e.target.value})} placeholder="M3"
            style={{ width:"100%", padding:"10px", border:"2px solid #ddd", borderRadius:8, fontSize:14, outline:"none", textAlign:"center", boxSizing:"border-box", background:data[keyM]?"#fff":"#fafafa" }}/>
        </div>
      </div>
    </div>
  );
  const yn = (key, label) => (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"12px 0", borderBottom:"1px solid #f0f0f0" }}>
      <div style={{ flex:1, fontSize:14, color:"#444", paddingRight:12 }}>{label}</div>
      <div style={{ display:"flex", gap:16, flexShrink:0 }}>
        {["Yes","No"].map(o=>(
          <label key={o} style={{ display:"flex", alignItems:"center", gap:5, fontSize:14, cursor:"pointer" }}>
            <input type="radio" name={key} value={o} checked={data[key]===o} onChange={()=>onChange({...data,[key]:o})} style={{ accentColor:BMK_COLOR }}/>
            {o}
          </label>
        ))}
      </div>
    </div>
  );
  const sec = t => <div style={{ fontWeight:700, fontSize:14, color:BMK_COLOR, margin:"16px 0 8px", paddingBottom:4, borderBottom:`2px solid ${BMK_COLOR}30` }}>{t}</div>;
  const co = (key, label) => (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"8px 0" }}>
      <div style={{ fontSize:13, color:"#444", flex:1 }}>{label}</div>
      <input value={data[key]||""} onChange={e=>onChange({...data,[key]:e.target.value})} placeholder=""
        style={{ width:90, padding:"7px 10px", border:"1px solid #ddd", borderRadius:8, fontSize:13, outline:"none", textAlign:"right" }}/>
    </div>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Measure & Record" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
          {sec("Central Heating Mode")}
          {gasRate("chGasRateFt","chGasRateM3","Gas Rate (FT3 / M3):")}
          {inp("chPressure","Gas inlet pressure (max rate) or burner operating pressure (max rate):","mbar")}
          {inp("chFlowTemp","Central heating flow temperature (C°):","°C")}
          {inp("chReturnTemp","Central heating return temperature (C°):","°C")}
        </div>
        <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
          {sec("Hot Water Mode")}
          {gasRate("hwGasRateFt","hwGasRateM3","Gas Rate (FT3 / M3):")}
          {inp("hwPressure","Gas inlet pressure (max rate) or burner operating pressure (max rate):","mbar")}
          {inp("hwColdInlet","Cold water inlet temperature (C°):","°C")}
          {inp("hwOutletTemp","Hot water outlet temperature (C°):","°C")}
          {inp("hwFlowRate","Flow rate ( l/min ):","l/min")}
          {yn("hwCheckedAll","Has hot water been checked at all outlets?")}
        </div>
        <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
          {sec("Combustion Analysis")}
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12 }}>
            <div>{co("coMin","Min CO:")} </div>
            <div>{co("coMax","Max CO:")}</div>
            <div>{co("co2Min","Min CO2:")}</div>
            <div>{co("co2Max","Max CO2:")}</div>
            <div>{co("ratioMin","Min CO/CO2 Ratio:")}</div>
            <div>{co("ratioMax","Max CO/CO2 Ratio:")}</div>
          </div>
        </div>
      </div>
      <BottomBar onHome={onHome} onNext={onNext}/>
    </div>
  );
}

