function BmkStepServices({ data, onChange, onNext, onBack, onHome }) {
  const services = data.services || Array(10).fill(null).map(()=>({
    date:"", engineerName:"", companyName:"", tel:"", gasSafeNo:"",
    coMaxRate:"", co2MaxRate:"", coMinRate:"", co2MinRate:"", comments:"", signature:""
  }));
  const update = (i, key, val) => {
    const s = services.map((svc,j) => j===i ? {...svc,[key]:val} : svc);
    onChange({...data, services:s});
  };
  const inp = (i,key,ph,type) => <input type={type||"text"} value={services[i][key]||""}
    onChange={e=>update(i,key,e.target.value)} placeholder={ph||""}
    style={{ width:"100%", boxSizing:"border-box", padding:"9px 11px", border:"1px solid #ddd", borderRadius:8, fontSize:13, outline:"none", marginBottom:2 }}/>;
  const lbl = t => <div style={{ fontSize:11, fontWeight:600, color:"#555", marginBottom:3, marginTop:8 }}>{t}</div>;

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Service Record (Optional)" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:12, paddingBottom:80 }}>
        <div style={{ background:"#fffbeb", border:"1.5px solid #f5c400", borderRadius:10, padding:"10px 12px", marginBottom:14, fontSize:13, color:"#444", lineHeight:1.5 }}>
          📋 The Service Record page will be included as <strong>page 2</strong> of the PDF. Fill in any services already completed, or leave blank and fill in later.
        </div>
        {services.map((svc, i) => (
          <div key={i} style={{ background:"#fff", borderRadius:10, padding:12, marginBottom:10, boxShadow:"0 1px 4px rgba(0,0,0,0.06)", borderLeft:`3px solid ${BMK_COLOR}` }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:8 }}>
              <div style={{ fontWeight:700, fontSize:14, color:BMK_COLOR }}>Service {i+1}</div>
              {svc.date && <div style={{ fontSize:12, color:"#888" }}>{svc.date}</div>}
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
              <div style={{ gridColumn:"1/-1" }}>{lbl("Date")}<input type="date" value={svc.date||""} onChange={e=>update(i,"date",e.target.value)}
                style={{ width:"100%", boxSizing:"border-box", padding:"9px 11px", border:"1px solid #ddd", borderRadius:8, fontSize:13, outline:"none" }}/></div>
              <div>{lbl("Engineers Name")}{inp(i,"engineerName","Full name")}</div>
              <div>{lbl("Company Name")}{inp(i,"companyName","Company")}</div>
              <div>{lbl("Telephone No")}{inp(i,"tel","Phone","tel")}</div>
              <div>{lbl("Gas Safe Register No")}{inp(i,"gasSafeNo","Gas Safe No")}</div>
            </div>
            {lbl("CO/CO₂ Readings")}
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr 1fr", gap:6 }}>
              <div><div style={{ fontSize:10, color:"#888", marginBottom:2 }}>CO max rate</div>{inp(i,"coMaxRate","ppm")}</div>
              <div><div style={{ fontSize:10, color:"#888", marginBottom:2 }}>CO₂ max rate</div>{inp(i,"co2MaxRate","%")}</div>
              <div><div style={{ fontSize:10, color:"#888", marginBottom:2 }}>CO min rate</div>{inp(i,"coMinRate","ppm")}</div>
              <div><div style={{ fontSize:10, color:"#888", marginBottom:2 }}>CO₂ min rate</div>{inp(i,"co2MinRate","%")}</div>
            </div>
            {lbl("Comments")}<textarea value={svc.comments||""} onChange={e=>update(i,"comments",e.target.value)} placeholder="Any comments..."
              rows={2} style={{ width:"100%", boxSizing:"border-box", padding:"9px 11px", border:"1px solid #ddd", borderRadius:8, fontSize:13, outline:"none", resize:"none", marginBottom:2 }}/>
          </div>
        ))}
      </div>
      <BottomBar onHome={onHome} onNext={onNext} nextLabel="Next"/>
    </div>
  );
}

function BmkStepSignature({ data, onChange, onNext, onBack, onHome }) {
  const today = new Date().toISOString().slice(0,10);
  const fmtDisplay = iso => { if (!iso) return ""; const d = new Date(iso+"T12:00:00"); if (isNaN(d)) return iso; return d.toLocaleDateString("en-GB", { weekday:"short", day:"2-digit", month:"short", year:"numeric" }); };
  useEffect(() => {
    const updates = {};
    if (!data.sigDate) updates.sigDate = today;
    if (!data.sigCustomerDate) updates.sigCustomerDate = today;
    if (Object.keys(updates).length) onChange({...data,...updates});
  }, []);

  const lbl = t => <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:6, marginTop:10 }}>{t}</div>;
  const sec = t => <div style={{ fontWeight:700, fontSize:14, color:BMK_COLOR, borderBottom:`2px solid ${BMK_COLOR}30`, paddingBottom:6, marginBottom:12, marginTop:16 }}>{t}</div>;

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Signatures" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
          <div style={{ display:"flex", alignItems:"flex-start", gap:10, padding:"12px 0", borderBottom:"1px solid #f0f0f0" }}>
            <input type="checkbox" id="dataProtection" checked={data.dataProtection||false}
              onChange={e=>onChange({...data,dataProtection:e.target.checked})}
              style={{ width:20, height:20, accentColor:BMK_COLOR, marginTop:2, flexShrink:0 }}/>
            <label htmlFor="dataProtection" style={{ fontSize:14, color:"#444", cursor:"pointer" }}>Data Protection</label>
          </div>
          {sec("Commissioning Engineer's Signature")}
          {lbl("Draw engineer signature below")}
          <SigPad value={data.sigEngineerImg} storageKey="gsc_engineer_sig" onChange={v=>onChange({...data,sigEngineerImg:v})}/>
          {lbl("Engineer printed name")}<input value={data.sigEngineerName||""} onChange={e=>onChange({...data,sigEngineerName:e.target.value})} placeholder="Full name"
            style={{ width:"100%", boxSizing:"border-box", padding:"11px 13px", border:"1px solid #ddd", borderRadius:8, fontSize:14, outline:"none", marginBottom:2 }}/>
          {lbl("Date")}<input type="date" value={data.sigDate||today} onChange={e=>onChange({...data,sigDate:e.target.value})}
            style={{ width:"100%", boxSizing:"border-box", padding:"11px 13px", border:"1px solid #ddd", borderRadius:8, fontSize:14, outline:"none" }}/>
          {data.sigDate && <div style={{ fontSize:12, color:"#888", marginTop:4 }}>{fmtDisplay(data.sigDate)}</div>}
        </div>

      </div>
      <BottomBar onHome={onHome} onNext={()=>onNext()} nextLabel="Next: Customer Signature"/>
    </div>
  );
}

