// ─── ATTACHMENTS STEP (shared by all cert flows) ────────────────────────────

function AttachmentsStep({ data, onChange, onNext, onBack, onHome, accentColor="#1d4a2e", nextLabel="Next: Signatures" }) {
  const imgRef = useRef(null);
  const pdfRef = useRef(null);
  const attachments = data.attachments || [];

  const addFile = (file, type) => {
    if (!file) return;
    if (file.size > 20 * 1024 * 1024) { alert("File must be under 20MB"); return; }
    const reader = new FileReader();
    reader.onload = ev => {
      const updated = [...attachments, { name: file.name, type, dataUrl: ev.target.result }];
      onChange({ ...data, attachments: updated });
    };
    reader.readAsDataURL(file);
  };

  const removeFile = (idx) => {
    const updated = attachments.filter((_, i) => i !== idx);
    onChange({ ...data, attachments: updated });
  };

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Attach Evidence" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
          <div style={{ fontSize:14, color:"#555", marginBottom:16, lineHeight:1.5 }}>
            Attach photos from your camera or import PDF files from flue gas analysers, manometers, etc. These will be added as extra pages in the certificate PDF.
          </div>
          <div style={{ display:"flex", gap:10, marginBottom:16, flexWrap:"wrap" }}>
            <button onClick={() => imgRef.current?.click()}
              style={{ flex:1, minWidth:140, padding:"14px 12px", background:accentColor, color:"#fff", border:"none", borderRadius:10, fontSize:14, fontWeight:600, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:8 }}>
              📷 Take Photo / Choose Image
            </button>
            <button onClick={() => pdfRef.current?.click()}
              style={{ flex:1, minWidth:140, padding:"14px 12px", background:"#374151", color:"#fff", border:"none", borderRadius:10, fontSize:14, fontWeight:600, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:8 }}>
              📄 Import PDF
            </button>
          </div>
          <input ref={imgRef} type="file" accept="image/*" onChange={e => { addFile(e.target.files?.[0], "image"); e.target.value=""; }} style={{ display:"none" }}/>
          <input ref={pdfRef} type="file" accept="application/pdf" onChange={e => { addFile(e.target.files?.[0], "pdf"); e.target.value=""; }} style={{ display:"none" }}/>

          {attachments.length > 0 && (
            <>
              <div style={{ fontSize:13, fontWeight:600, color:"#333", marginBottom:10 }}>
                {attachments.length} file{attachments.length !== 1 ? "s" : ""} attached
              </div>
              <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(120px, 1fr))", gap:10 }}>
                {attachments.map((att, i) => (
                  <div key={i} style={{ position:"relative", background:"#f9f9f9", borderRadius:8, border:"1px solid #e5e7eb", overflow:"hidden" }}>
                    {att.type === "image"
                      ? <img src={att.dataUrl} alt={att.name} style={{ width:"100%", height:100, objectFit:"cover", display:"block" }}/>
                      : <div style={{ width:"100%", height:100, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", background:"#f0f0f0" }}>
                          <span style={{ fontSize:28 }}>📄</span>
                          <span style={{ fontSize:10, color:"#666", marginTop:4, padding:"0 6px", textAlign:"center", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", maxWidth:"100%" }}>{att.name}</span>
                        </div>
                    }
                    <button onClick={() => removeFile(i)}
                      style={{ position:"absolute", top:4, right:4, width:22, height:22, borderRadius:"50%", background:"rgba(0,0,0,0.6)", color:"#fff", border:"none", cursor:"pointer", fontSize:13, display:"flex", alignItems:"center", justifyContent:"center", lineHeight:1 }}>×</button>
                  </div>
                ))}
              </div>
            </>
          )}

          {attachments.length === 0 && (
            <div style={{ textAlign:"center", padding:"20px 0", color:"#aaa", fontSize:13 }}>
              No files attached yet — this step is optional
            </div>
          )}
        </div>
      </div>
      <BottomBar onHome={onHome} onNext={onNext} nextLabel={nextLabel}/>
    </div>
  );
}

// ─── APPEND ATTACHMENT PAGES TO PDF ─────────────────────────────────────

async function appendAttachmentPages(pdf, attachments, orientation) {
  if (!attachments || attachments.length === 0) return;
  const isLandscape = orientation === "landscape";
  const pdfW = isLandscape ? 297 : 210;
  const pdfH = isLandscape ? 210 : 297;
  const margin = 10;
  const usableW = pdfW - margin * 2;
  const usableH = pdfH - margin * 2;
  const titleH = 8;

  const images = attachments.filter(a => a.type === "image");
  const pdfs = attachments.filter(a => a.type === "pdf");

  // Add image pages (2 per page)
  for (let i = 0; i < images.length; i += 2) {
    pdf.addPage();
    pdf.setFontSize(10);
    pdf.setFont(undefined, "bold");
    pdf.text("Attached Evidence", margin, margin + 4);
    const slotH = (usableH - titleH - 4) / 2;
    for (let j = 0; j < 2 && (i + j) < images.length; j++) {
      const att = images[i + j];
      try {
        const img = await new Promise((res, rej) => {
          const im = new Image();
          im.onload = () => res(im);
          im.onerror = rej;
          im.src = att.dataUrl;
        });
        const ratio = img.width / img.height;
        let drawW = usableW;
        let drawH = drawW / ratio;
        if (drawH > slotH - 6) { drawH = slotH - 6; drawW = drawH * ratio; }
        const x = margin + (usableW - drawW) / 2;
        const y = margin + titleH + 2 + j * slotH;
        pdf.addImage(att.dataUrl, "JPEG", x, y, drawW, drawH);
        pdf.setFontSize(7);
        pdf.setFont(undefined, "normal");
        pdf.text(att.name || "Photo", x, y + drawH + 4);
      } catch(e) { /* skip broken image */ }
    }
  }

  // Add PDF pages (render each page via pdf.js)
  for (let i = 0; i < pdfs.length; i++) {
    pdf.addPage();
    pdf.setFontSize(10);
    pdf.setFont(undefined, "bold");
    pdf.text("Attached Evidence — " + (pdfs[i].name || "Document"), margin, margin + 4);

    try {
      if (!window.pdfjsLib) {
        await new Promise((res, rej) => {
          const s = document.createElement("script");
          s.src = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js";
          s.onload = () => {
            window.pdfjsLib.GlobalWorkerOptions.workerSrc = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";
            res();
          };
          s.onerror = rej;
          document.head.appendChild(s);
        });
      }

      const base64 = pdfs[i].dataUrl.split(",")[1];
      const binary = atob(base64);
      const bytes = new Uint8Array(binary.length);
      for (let b = 0; b < binary.length; b++) bytes[b] = binary.charCodeAt(b);

      const pdfDoc = await window.pdfjsLib.getDocument({ data: bytes }).promise;
      const numPages = pdfDoc.numPages;

      for (let p = 1; p <= numPages; p++) {
        if (p > 1) {
          pdf.addPage();
          pdf.setFontSize(10);
          pdf.setFont(undefined, "bold");
          pdf.text("Attached Evidence — " + (pdfs[i].name || "Document") + " (page " + p + ")", margin, margin + 4);
        }
        const page = await pdfDoc.getPage(p);
        const viewport = page.getViewport({ scale: 2 });
        const canvas = document.createElement("canvas");
        canvas.width = viewport.width;
        canvas.height = viewport.height;
        await page.render({ canvasContext: canvas.getContext("2d"), viewport }).promise;

        const imgData = canvas.toDataURL("image/jpeg", 0.92);
        const ratio = canvas.width / canvas.height;
        let drawW = usableW;
        let drawH = drawW / ratio;
        if (drawH > usableH - titleH - 4) { drawH = usableH - titleH - 4; drawW = drawH * ratio; }
        const x = margin + (usableW - drawW) / 2;
        const y = margin + titleH + 2;
        pdf.addImage(imgData, "JPEG", x, y, drawW, drawH);
      }
    } catch(e) {
      pdf.setFontSize(14);
      pdf.setFont(undefined, "normal");
      pdf.text("PDF file: " + (pdfs[i].name || "Unknown"), margin, margin + 20);
      pdf.text("(Could not render preview)", margin, margin + 30);
    }
  }
}

// ─── SHARED SIGNATURE PAD & STEP (used by all new cert types) ────────────────

function SigPad({ value, onChange, storageKey }) {
  const canvasRef = useRef(null);
  const drawing = useRef(false);

  // Pre-fill from stored engineer sig if a storageKey is given
  useEffect(() => {
    if (!canvasRef.current) return;
    const stored = storageKey
      ? (() => { try { return localStorage.getItem(sk(storageKey)) || null; } catch(e) { return null; } })()
      : null;
    const src = value || stored;
    if (src) {
      const img = new Image();
      img.onload = () => {
        const ctx = canvasRef.current && canvasRef.current.getContext("2d");
        if (ctx) { ctx.clearRect(0,0,600,150); ctx.drawImage(img,0,0,600,150); }
      };
      img.src = src;
    }
  }, []);

  const getPos = (e, canvas) => {
    const rect = canvas.getBoundingClientRect();
    const src = e.touches ? e.touches[0] : e;
    return [(src.clientX - rect.left) * (canvas.width / rect.width),
            (src.clientY - rect.top)  * (canvas.height / rect.height)];
  };
  const startDraw = e => {
    drawing.current = true;
    const [x,y] = getPos(e, canvasRef.current);
    const ctx = canvasRef.current.getContext("2d");
    ctx.beginPath(); ctx.moveTo(x,y);
  };
  const draw = e => {
    if (!drawing.current) return;
    e.preventDefault();
    const [x,y] = getPos(e, canvasRef.current);
    const ctx = canvasRef.current.getContext("2d");
    ctx.lineWidth = 2.2; ctx.strokeStyle = "#1a1a2e";
    ctx.lineTo(x,y); ctx.stroke();
  };
  const endDraw = () => {
    if (!drawing.current) return;
    drawing.current = false;
    setTimeout(() => {
      if (!canvasRef.current) return;
      const dataUrl = canvasRef.current.toDataURL("image/png");
      if (storageKey) { try { localStorage.setItem(sk(storageKey), dataUrl); } catch(e) {} }
      onChange(dataUrl);
    }, 50);
  };
  const clear = () => {
    const c = canvasRef.current;
    if (c) c.getContext("2d").clearRect(0,0,c.width,c.height);
    onChange(null);
  };

  return (
    <div>
      <div style={{ border:"1.5px solid #ccc", borderRadius:10, overflow:"hidden", background:"#fff" }}>
        <canvas ref={canvasRef} width={600} height={150}
          style={{ display:"block", width:"100%", touchAction:"none", cursor:"crosshair" }}
          onMouseDown={startDraw} onMouseMove={draw} onMouseUp={endDraw} onMouseLeave={endDraw}
          onTouchStart={startDraw} onTouchMove={draw} onTouchEnd={endDraw}/>
      </div>
      <button onClick={clear}
        style={{ marginTop:6, padding:"5px 16px", background:"none", border:"1.5px solid #e5e7eb",
                 borderRadius:8, fontSize:12, color:"#888", cursor:"pointer" }}>Clear</button>
    </div>
  );
}

// Shared signature step used by: LPG, Leisure, Commercial GSC, Cool Off,
// GISR, Catering, Gas Test/Purge

// ─── SHARED CUSTOMER SIGNATURE STEP (used by all cert types) ─────────────────

function CustomerSigStep({ data, onChange, onNext, onBack, onHome, accentColor="#1d4a2e", nextLabel="Preview PDF", imgKeyOverride, nameKeyOverride, dateKeyOverride }) {
  const today = new Date().toISOString().slice(0,10);

  useEffect(() => {
    if (!data.sigCustomerDate) onChange({...data, sigCustomerDate: today});
  }, []);

  const fmtDisplay = iso => {
    if (!iso) return "";
    const d = new Date(iso);
    if (isNaN(d)) return iso;
    const months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
    return String(d.getDate()).padStart(2,"0")+"-"+months[d.getMonth()]+"-"+d.getFullYear();
  };

  const lbl = t => <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:6, marginTop:10 }}>{t}</div>;

  // Choose the right field names — most certs use sigCustomerImg/sigCustomerName/sigCustomerDate
  // CoolOff uses sigClientImg/sigClient/sigClientDate
  // GTP uses sigResponsibleImg/sigResponsible
  const imgKey  = imgKeyOverride  || (data.sigClientImg  !== undefined ? "sigClientImg"  : "sigCustomerImg");
  const nameKey = nameKeyOverride || (data.sigClient     !== undefined ? "sigClient"     : "sigCustomerName");
  const dateKey = dateKeyOverride || (data.sigClientDate !== undefined ? "sigClientDate" : "sigCustomerDate");

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Customer Signature" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
          <div style={{ fontWeight:700, fontSize:16, color:accentColor, borderBottom:`2px solid ${accentColor}30`, paddingBottom:8, marginBottom:14 }}>
            Customer / Responsible Person
          </div>
          <div style={{ fontSize:13, color:"#555", lineHeight:1.6, marginBottom:16, background:"#f9f9f9", borderRadius:8, padding:"10px 12px" }}>
            Please sign below to confirm satisfactory demonstration and receipt of documentation.
          </div>
          {lbl("Draw customer signature below")}
          <SigPad
            value={data[imgKey]}
            onChange={v => onChange({...data, [imgKey]: v})}
          />
          {lbl("Customer printed name")}
          <input
            value={data[nameKey]||""}
            onChange={e => onChange({...data, [nameKey]: e.target.value})}
            placeholder="Customer full name"
            style={{ width:"100%", boxSizing:"border-box", padding:"12px 14px", border:"1px solid #ddd", borderRadius:8, fontSize:15, outline:"none", marginBottom:2 }}
          />
          {lbl("Date")}
          <input
            type="date"
            value={data[dateKey]||today}
            onChange={e => onChange({...data, [dateKey]: e.target.value})}
            style={{ width:"100%", boxSizing:"border-box", padding:"12px 14px", border:"1px solid #ddd", borderRadius:8, fontSize:15, outline:"none" }}
          />
          {data[dateKey] && <div style={{ fontSize:12, color:"#888", marginTop:4 }}>{fmtDisplay(data[dateKey])}</div>}
        </div>
      </div>
      <BottomBar onHome={onHome} onNext={onNext} nextLabel={nextLabel}/>
    </div>
  );
}

function SharedSigStep({ data, onChange, onNext, onBack, onHome, accentColor="#1d4a2e", certTitle="Certificate" }) {
  const today = new Date().toISOString().slice(0,10);

  // Auto-populate dates on first render
  useEffect(() => {
    if (!data.sigDate) onChange({...data, sigDate: today});
  }, []);

  const fmtDisplay = iso => {
    if (!iso) return "";
    const d = new Date(iso);
    if (isNaN(d)) return iso;
    const months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
    return String(d.getDate()).padStart(2,"0")+"-"+months[d.getMonth()]+"-"+d.getFullYear();
  };

  const sec = t => (
    <div style={{ fontWeight:700, fontSize:14, color:accentColor,
                  borderBottom:`2px solid ${accentColor}30`, paddingBottom:6, marginBottom:12, marginTop:16 }}>{t}</div>
  );
  const lbl = t => <div style={{ fontSize:12, fontWeight:600, color:"#555", marginBottom:6, marginTop:10 }}>{t}</div>;

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Signatures & Dates" onBack={onBack} onHome={onHome}/>
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>

        {/* Engineer signature */}
        <div style={{ background:"#fff", borderRadius:12, padding:16, marginBottom:12, boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
          {sec("Report Issued By (Engineer)")}
          {lbl("Draw engineer signature below")}
          <SigPad
            value={data.sigEngineerImg}
            storageKey="gsc_engineer_sig"
            onChange={v => onChange({...data, sigEngineerImg:v})}
          />
          {lbl("Printed name")}<input value={data.sigEngineerName||""} onChange={e=>onChange({...data,sigEngineerName:e.target.value})}
            placeholder="Engineer full name"
            style={{ width:"100%", boxSizing:"border-box", padding:"11px 13px", border:"1px solid #ddd", borderRadius:8, fontSize:14, outline:"none", marginBottom:2 }}/>
          {lbl("Date")}
          <input type="date" value={data.sigDate||today} onChange={e=>onChange({...data,sigDate:e.target.value})}
            style={{ width:"100%", boxSizing:"border-box", padding:"11px 13px", border:"1px solid #ddd", borderRadius:8, fontSize:14, outline:"none" }}/>
          {data.sigDate && <div style={{ fontSize:12, color:"#888", marginTop:4 }}>{fmtDisplay(data.sigDate)}</div>}
        </div>

      </div>
      <BottomBar onHome={onHome} onNext={onNext} nextLabel="Next: Customer Signature"/>
    </div>
  );
}

function GwSignaturePad({ onSign }) {
  const canvasRef = useRef(null);
  const drawing = useRef(false);
  const getPos = (e, canvas) => {
    const rect = canvas.getBoundingClientRect();
    const src = e.touches ? e.touches[0] : e;
    return [(src.clientX - rect.left) * (canvas.width / rect.width), (src.clientY - rect.top) * (canvas.height / rect.height)];
  };
  const startDraw = e => { drawing.current=true; const [x,y]=getPos(e,canvasRef.current); const ctx=canvasRef.current.getContext("2d"); ctx.beginPath(); ctx.moveTo(x,y); };
  const draw = e => { if(!drawing.current) return; e.preventDefault(); const [x,y]=getPos(e,canvasRef.current); const ctx=canvasRef.current.getContext("2d"); ctx.lineWidth=2; ctx.strokeStyle="#1a1a2e"; ctx.lineTo(x,y); ctx.stroke(); };
  const endDraw = () => {
    if(!drawing.current) return;
    drawing.current=false;
    setTimeout(()=>{
      if(canvasRef.current) {
        const dataUrl = canvasRef.current.toDataURL("image/png");
        try { localStorage.setItem(sk("gsc_engineer_sig"), dataUrl); } catch(e) {}
        onSign(dataUrl);
      }
    }, 50);
  };
  const clear = () => { const c=canvasRef.current; c.getContext("2d").clearRect(0,0,c.width,c.height); onSign(null); };
  return (
    <div>
      <div style={{ border:"1.5px solid #e5e7eb", borderRadius:10, overflow:"hidden", background:"#fff" }}>
        <canvas ref={canvasRef} width={600} height={150} style={{ display:"block", width:"100%", touchAction:"none", cursor:"crosshair" }}
          onMouseDown={startDraw} onMouseMove={draw} onMouseUp={endDraw} onMouseLeave={endDraw}
          onTouchStart={startDraw} onTouchMove={draw} onTouchEnd={endDraw}/>
      </div>
      <button onClick={clear} style={{ marginTop:8, padding:"6px 18px", background:"none", border:`1.5px solid #e5e7eb`, borderRadius:8, fontSize:13, color:"#888", cursor:"pointer" }}>Clear</button>
    </div>
  );
}

