              <tr>
                <th style={{ border:"1px solid #999", padding:"6px 10px", background:"#f0f0f0", fontWeight:700, width:"28%", textAlign:"center" }}>Item that could be affected by main work</th>
                <th style={{ border:"1px solid #999", padding:"6px 10px", background:"#f0f0f0", fontWeight:700, width:"12%", textAlign:"center" }}>Quantity</th>
                <th style={{ border:"1px solid #999", padding:"6px 10px", background:"#f0f0f0", fontWeight:700, width:"28%", textAlign:"center" }}>Location</th>
                <th style={{ border:"1px solid #999", padding:"6px 10px", background:"#f0f0f0", fontWeight:700, width:"16%", textAlign:"center" }}>Enabling Work (Yes/No)</th>
                <th style={{ border:"1px solid #999", padding:"6px 10px", background:"#f0f0f0", fontWeight:700, width:"16%", textAlign:"center" }}>Decommission (Yes/No)</th>
              </tr>
