// ─── SHARED CONTACT PICKER MODAL ─────────────────────────────────────────────
// Used by all client/installation detail screens to pick from in-app contacts

function ContactPickerModal({ onSelect, onClose, title="Choose a contact" }) {
  const [search, setSearch] = useState("");
  const contacts = (() => {
    try { return JSON.parse(localStorage.getItem(sk("client_contacts")) || "[]"); }
    catch { return []; }
  })();

  const filtered = contacts.filter(c => {
    const q = search.toLowerCase();
    return !q || (c.name||"").toLowerCase().includes(q)
      || (c.company||"").toLowerCase().includes(q)
      || (c.phone||"").includes(q)
      || (c.addr||"").toLowerCase().includes(q);
  });

  return (
    <div style={{ position:"fixed", inset:0, zIndex:3000, display:"flex", flexDirection:"column",
      background:"rgba(0,0,0,0.55)", fontFamily:"'Segoe UI',sans-serif" }}
      onClick={e=>{ if(e.target===e.currentTarget) onClose(); }}>
      <div style={{ flex:1, display:"flex", flexDirection:"column", margin:"48px 0 0",
        background:LIGHT_BG, borderRadius:"20px 20px 0 0", overflow:"hidden", boxShadow:"0 -8px 40px rgba(0,0,0,0.3)" }}>
        {/* Header */}
        <div style={{ background:"#1d4a2e", padding:"14px 16px", display:"flex", alignItems:"center", gap:12 }}>
          <span style={{ color:"#fff200", fontWeight:700, fontSize:16, flex:1 }}>👥 {title}</span>
          <button onClick={onClose}
            style={{ background:"rgba(255,255,255,0.18)", border:"none", borderRadius:"50%", width:32, height:32,
              color:"#fff", fontSize:20, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", lineHeight:1 }}>×</button>
        </div>
        {/* Search */}
        <div style={{ padding:"10px 14px", background:"#fff", borderBottom:"1px solid #e8eee8" }}>
          <input value={search} onChange={e=>setSearch(e.target.value)}
            placeholder="🔍  Search by name, company or phone..."
            autoFocus
            style={{ width:"100%", boxSizing:"border-box", padding:"10px 13px", border:"2px solid #1d4a2e30",
              borderRadius:10, fontSize:14, outline:"none", fontFamily:"inherit" }}/>
        </div>
        {/* List */}
        <div style={{ flex:1, overflowY:"auto", padding:"8px 12px 24px" }}>
          {contacts.length === 0 ? (
            <div style={{ textAlign:"center", padding:"48px 24px" }}>
              <div style={{ fontSize:44, marginBottom:12 }}>👥</div>
              <div style={{ fontWeight:700, fontSize:16, color:"#222", marginBottom:8 }}>No contacts imported yet</div>
              <div style={{ fontSize:13, color:"#888", lineHeight:1.6 }}>
                Go to <strong>Client Details</strong> on the dashboard to import your contacts from your phone.
              </div>
            </div>
          ) : filtered.length === 0 ? (
            <div style={{ textAlign:"center", padding:"32px 24px", color:"#888", fontSize:14 }}>
              No contacts match "{search}"
            </div>
          ) : filtered.map((c, i) => (
            <div key={c.id||i} onClick={()=>onSelect(c)}
              style={{ background:"#fff", borderRadius:10, padding:"12px 14px", marginBottom:8, cursor:"pointer",
                boxShadow:"0 1px 4px rgba(0,0,0,0.06)", borderLeft:"4px solid #1d4a2e",
                display:"flex", alignItems:"center", gap:12, transition:"background 0.12s" }}
              onMouseEnter={e=>e.currentTarget.style.background="#f0f9f4"}
              onMouseLeave={e=>e.currentTarget.style.background="#fff"}>
              <div style={{ width:40, height:40, borderRadius:"50%", background:"#1d4a2e18",
                display:"flex", alignItems:"center", justifyContent:"center", fontSize:18, flexShrink:0 }}>
                👤
              </div>
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ fontWeight:700, fontSize:15, color:"#222", marginBottom:1 }}>{c.name||"—"}</div>
                {c.company && <div style={{ fontSize:12, color:"#1d4a2e", fontWeight:600, marginBottom:1 }}>{c.company}</div>}
                {c.phone  && <div style={{ fontSize:12, color:"#555" }}>📞 {c.phone}</div>}
                {c.addr   && <div style={{ fontSize:11, color:"#aaa", marginTop:1, overflow:"hidden", whiteSpace:"nowrap", textOverflow:"ellipsis" }}>{c.addr}</div>}
              </div>
              <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ flexShrink:0 }}>
                <path d="M5 3L11 8L5 13" stroke="#ccc" strokeWidth="2" strokeLinecap="round"/>
              </svg>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// Helper: parse an in-app contact into the standard address fields
function contactToFields(c) {
  // Try to split c.addr into addr1 / addr2 / addr3 / postcode
  const parts = (c.addr || "").split(",").map(p => p.trim()).filter(Boolean);
  // Last part that looks like a postcode
  const postcodeRe = /^[A-Z]{1,2}[0-9][0-9A-Z]?\s*[0-9][A-Z]{2}$/i;
  let postcode = "", addr1 = "", addr2 = "", addr3 = "";
  const remaining = [...parts];
  const pcIdx = remaining.findIndex(p => postcodeRe.test(p.replace(/\s+/,"")));
  if (pcIdx !== -1) { postcode = remaining.splice(pcIdx, 1)[0]; }
  else if (remaining.length && postcodeRe.test(remaining[remaining.length-1].replace(/\s+/,""))) {
    postcode = remaining.pop();
  }
  addr1 = remaining[0] || "";
  addr2 = remaining[1] || "";
  addr3 = remaining[2] || "";
  return { name: c.name||"", phone: c.phone||"", email: c.email||"", company: c.company||"",
           addr1, addr2, addr3, postcode };
}


// ─── APPLIANCE MAKE / MODEL MEMORY ───────────────────────────────────────────

const APPLIANCE_MEMORY_KEY = "wlg_appliance_memory";

function getApplianceMemory() {
  try { return JSON.parse(localStorage.getItem(APPLIANCE_MEMORY_KEY) || "{}"); } catch { return {}; }
}

// Save a make or model to memory.
// category: "make" | "model"  value: the string to remember
function rememberApplianceValue(category, value) {
  if (!value || !value.trim()) return;
  const v = value.trim();
  const mem = getApplianceMemory();
  if (!mem[category]) mem[category] = [];
  if (!mem[category].includes(v)) {
    // Keep newest-first, max 60 entries
    mem[category] = [v, ...mem[category].filter(x => x !== v)].slice(0, 60);
    try { localStorage.setItem(APPLIANCE_MEMORY_KEY, JSON.stringify(mem)); } catch {}
  }
}

function getApplianceSuggestions(category) {
  const mem = getApplianceMemory();
  return mem[category] || [];
}

// Standalone make/model input with datalist autocomplete
// Props: value, onChange, onBlur(optional), placeholder, category("make"|"model"), inputStyle
function MakeModelInput({ value, onChange, onBlur, placeholder, category, inputStyle, id }) {
  const stableId = useRef(id || ("wlg-mm-" + category + "-" + Date.now().toString(36)));
  const listId = stableId.current;
  const suggestions = getApplianceSuggestions(category);

  function handleBlur(e) {
    const v = e.target.value.trim();
    if (v) rememberApplianceValue(category, v);
    if (onBlur) onBlur(e);
  }

  return (
    <>
      <input
        value={value || ""}
        onChange={e => onChange(e.target.value)}
        onBlur={handleBlur}
        placeholder={placeholder || (category === "make" ? "e.g. Worcester" : "e.g. Greenstar 30i")}
        list={listId}
        autoComplete="off"
        style={inputStyle || { width:"100%", boxSizing:"border-box", padding:"11px 13px",
          border:"1px solid #ddd", borderRadius:8, fontSize:14,
          fontFamily:"'Segoe UI',sans-serif", outline:"none", marginBottom:2 }}
      />
      <datalist id={listId}>
        {suggestions.map((s, i) => <option key={i} value={s}/>)}
      </datalist>
    </>
  );
}

async function openPhoneContacts(onSelect) {
  if (!("contacts" in navigator && "ContactsManager" in window)) {
    return "unsupported";
  }
  try {
    const props = ["name", "tel", "email", "address"];
    const results = await navigator.contacts.select(props, { multiple: false });
    if (!results || results.length === 0) return "cancelled";
    const c = results[0];
    const addr = c.address?.[0] || {};
    onSelect({
      name: c.name?.[0] || "",
      tel: c.tel?.[0] || "",
      email: c.email?.[0] || "",
      addr1: addr.addressLine?.[0] || addr.streetAddress || "",
      addr2: addr.city || addr.addressLine?.[1] || "",
      addr3: addr.region || addr.addressLine?.[2] || "",
      postcode: addr.postalCode || "",
    });
    return "ok";
  } catch(e) {
    if (e.name === "SecurityError" || e.name === "InvalidStateError") return "blocked";
    return "error";
  }
}


// Step 2: Client + Installation Details
function StepClientDetails({ data, onChange, onNext, onBack, onHome }) {
  const [errorMsg, setErrorMsg] = useState("");

  const copy = () => onChange({...data, instName:data.clientName, instAddr1:data.clientAddr1, instAddr2:data.clientAddr2, instAddr3:data.clientAddr3, instPostcode:data.clientPostcode, instTel:data.clientTel});

  const [pickerTarget, setPickerTarget] = useState(null); // "client"|"inst"|null

  const handlePickContact = (target, c) => {
    const f = contactToFields(c);
    if (target === "client") {
      onChange({...data, clientName:f.name, clientAddr1:f.addr1, clientAddr2:f.addr2, clientAddr3:f.addr3, clientPostcode:f.postcode, clientTel:f.phone, clientEmail:f.email});
    } else {
      onChange({...data, instName:f.name, instAddr1:f.addr1, instAddr2:f.addr2, instAddr3:f.addr3, instPostcode:f.postcode, instTel:f.phone});
    }
    setPickerTarget(null);
  };

  const ContactBtn = ({ target }) => (
    <button onClick={() => setPickerTarget(target)} title="Import from Contacts"
      style={{ background:"rgba(255,255,255,0.25)", border:"2px solid rgba(255,255,255,0.8)", borderRadius:8, cursor:"pointer", padding:"4px 10px", display:"flex", alignItems:"center", gap:6 }}>
      <svg width="20" height="20" viewBox="0 0 28 28" fill="none">
        <circle cx="14" cy="10" r="5" stroke="white" strokeWidth="1.8"/>
        <path d="M5 24c0-5 4-8 9-8s9 3 9 8" stroke="white" strokeWidth="1.8" strokeLinecap="round"/>
        <circle cx="22" cy="22" r="5" fill="white"/>
        <path d="M22 19.5v5M19.5 22h5" stroke={BLUE} strokeWidth="1.8" strokeLinecap="round"/>
      </svg>
      <span style={{ color:"#fff", fontSize:12, fontWeight:600 }}>Contacts</span>
    </button>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="Client & Installation Details" onBack={onBack}/>
      <div style={{ flex:1, overflowY:"auto" }}>
        {errorMsg && (
          <div style={{ background:"#fff3cd", color:"#856404", padding:"10px 16px", fontSize:13, borderBottom:"1px solid #ffc107" }}>
            ⚠️ {errorMsg}
          </div>
        )}
        <SectionHeader title="Client Details" actions={[<ContactBtn key="cp" target="client"/>]}/>
        {[["clientName","Name"],["clientAddr1","Address line 1"],["clientAddr2","Address line 2"],["clientAddr3","Address line 3"],["clientPostcode","Postcode"],["clientTel","Telephone"],["clientEmail","Email"]].map(([k,p])=>(
          <FormInput key={k} placeholder={p} value={data[k]||""} onChange={v=>onChange({...data,[k]:v})}/>
        ))}
        <SectionHeader title="Installation Details" actions={[
          <button key="copy" onClick={copy} style={{ background:"#fff", border:"none", borderRadius:6, padding:"4px 10px", fontSize:13, fontWeight:600, color:BLUE, cursor:"pointer" }}>Copy</button>,
          <ContactBtn key="cp" target="inst"/>
        ]}/>
        {[["instName","Name"],["instAddr1","Address line 1"],["instAddr2","Address line 2"],["instAddr3","Address line 3"],["instPostcode","Postcode"],["instTel","Telephone"]].map(([k,p])=>(
          <FormInput key={k} placeholder={p} value={data[k]||""} onChange={v=>onChange({...data,[k]:v})}/>
        ))}
        <div style={{ height:20 }}/>
      </div>
      <BottomBar onHome={onHome} onNext={onNext}/>
      {pickerTarget && <ContactPickerModal
        title={pickerTarget==="client" ? "Choose Client" : "Choose Installation"}
        onSelect={c => handlePickContact(pickerTarget, c)}
        onClose={()=>setPickerTarget(null)}/>}
    </div>
  );
}

// Step 3: Appliance List
function StepApplianceList({ appliances, onAdd, onEdit, onDelete, onNext, onBack, onHome }) {
  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100dvh", background:LIGHT_BG, fontFamily:"'Segoe UI',sans-serif" }}>
      <Header title="" onBack={onBack}
        right={
          <div style={{ display:"flex", gap:12, alignItems:"center" }}>
            {appliances.length>0 && <button onClick={onDelete} style={{ background:"none", border:"none", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer" }}>DELETE</button>}
            <button onClick={onAdd} style={{ background:"none", border:"none", color:"#fff", fontSize:24, cursor:"pointer", lineHeight:1 }}>+</button>
          </div>
        }
      />
      <div style={{ flex:1, overflowY:"auto", padding:16, paddingBottom:80 }}>
        <p style={{ color:"#aaa", fontSize:14, marginBottom:12 }}>Appliance List :</p>
        {appliances.map((a,i)=>(
          <div key={i} onClick={()=>onEdit(i)} style={{ background:"#fff", borderRadius:10, padding:"14px 16px", marginBottom:10, display:"flex", alignItems:"center", justifyContent:"space-between", boxShadow:"0 2px 8px rgba(0,0,0,0.06)", cursor:"pointer" }}>
            <span style={{ fontSize:15, fontFamily:"'Segoe UI',sans-serif" }}>{a.type||a.location||`Appliance ${i+1}`}</span>
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M5 3L10 8L5 13" stroke="#bbb" strokeWidth="2" strokeLinecap="round"/></svg>
          </div>
        ))}
      </div>
      <BottomBar onHome={onHome} onNext={onNext}/>
    </div>
  );
}

