  function handleRenew(rec) {
    if (!rec) return;
    const type = rec.type || "gsc";
    if (type === "gsc" || !rec.type) {
      // Pre-populate GSC state from existing record, clear signatures + dates
      setCertData({ ...(rec.certData || {}), certRef: "" });
      setAppliances(rec.appliances ? rec.appliances.map(a => ({ ...a, co:"", co2:"", safeToUse:"YES", isServiced:"YES" })) : []);
      setFaults([]);
      setFinalChecks({ ...(rec.finalChecks || {}), inspectionDate: (() => { const d = new Date(); d.setFullYear(d.getFullYear()+1); return d; })() });
      setSignatureData({});
      setScreen("gsc");
      setSubScreen("clientDetails");
    } else if (type === "bs") {
      // Pre-populate BS state from existing record, clear signatures
      setServiceData({ ...(rec.serviceData || {}), certRef: "" });
      setBsSigData({});
      setScreen("bs");
      setBsSubScreen("clientDetails");
    }
    else {
      // New cert types — pre-populate from existing record, clear cert ref + sigs + renewal date
      const f = rec.form || {};
      const today = new Date().toISOString().slice(0,10);
      // Compute next inspection = 1 year from saved date (or today)
      const base = rec.savedAt ? new Date(rec.savedAt) : new Date();
      const nextYear = new Date(base.getFullYear()+1, base.getMonth(), base.getDate()).toISOString().slice(0,10);

      const preloaded = {
        ...f,
        // Clear cert identifiers
        certRef: "",
        certNo: "",
        // Clear signatures and dates ready for new signing
        sigEngineerImg: null,
        sigCustomerImg: null,
        sigOperativeImg: null,
        sigResponsibleImg: null,
        sigClientImg: null,
        sigDate: today,
        sigCustomerDate: today,
        sigEngDate: today,
        sigClientDate: today,
        // Clear faults from previous inspection
        faults: Array(5).fill(null).map(()=>({})),
        // Advance next inspection date by 1 year
        nextInspection: nextYear,
        // Keep all client/installation/engineer details pre-filled
      };
      setRenewInitData(preloaded);

      const screenMap = {
        leisure_gsc:          "leisureRecord",
        lpg_gsc:              "lpgRecord",
        cooling_off:          "coolingOff",
        commercial_gsc:       "commercialGSC",
        gas_install_report:   "gasInstallReport",
        catering_inspection:  "cateringInspection",
        gas_test_purge:       "gasTestPurge",
        benchmark:            "benchmark",
      };
      const target = screenMap[type];
      if (target) {
        setScreen(target);
      } else {
        setScreen("newJob");
      }
    }
  }
