  useEffect(() => {
    try { localStorage.setItem(sk("yearly_reports"), JSON.stringify(yearlyReports)); } catch {}
  }, [yearlyReports]);

  // Auto-rebuild yearly reports whenever monthly reports change
  useEffect(() => {
    if (!accountReports.length) return;
    const years = [...new Set(accountReports.map(r => r.createdAt ? new Date(r.createdAt).getFullYear() : null).filter(Boolean))];
    if (!years.length) return;
    const doRebuild = () => {
      setYearlyReports(prev => {
        let updated = [...prev];
        for (const year of years) {
          const yearly = buildYearlyReport(year, accountReports);
          if (yearly) {
            const idx = updated.findIndex(y => y.year === year);
            if (idx >= 0) updated[idx] = yearly;
            else updated = [yearly, ...updated];
          }
        }
        return updated;
      });
    };
    if (window.XLSX) {
      doRebuild();
    } else {
      const s = document.createElement("script");
      s.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
      s.onload = doRebuild;
      document.head.appendChild(s);
    }
  }, [accountReports]); // re-run whenever monthly reports change

